      e.preventDefault();
      var c=getXY(e); dPosRef.current=c;
      var el=svgRef.current&&svgRef.current.querySelector("#tkn-"+dIdRef.current);
      if (el) el.setAttribute("transform","translate("+c.x+","+c.y+")");
